#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long W, X, Y, Z;
        scanf("%lld %lld %lld %lld", &W, &X, &Y, &Z);
        long long result = W + Z * (X - Y);
        printf("%lld\n", result);
    }
    return 0;
}

